// Build the executor.sh command from input parameters
const input = $input.first().json;
const capability = input.capability || 'agent-general';
const prompt = (input.prompt || 'No prompt provided').replace(/'/g, "'\\''");
const sessionId = input.session_id || '';
const safetyMode = input.safety_mode || 'readonly';

// Validate capability
const validCapabilities = ['agent-infra-check', 'agent-research', 'agent-troubleshoot', 'agent-general'];
if (!validCapabilities.includes(capability)) {
  return [{ json: { error: `Invalid capability: ${capability}. Valid: ${validCapabilities.join(', ')}` } }];
}

// Build command — UPDATE THIS PATH to match your installation
let cmd = `${process.env.PROJECT_DIR || '/path/to/project'}/.claude/jobs/executor.sh --job ${capability} --param "prompt=${prompt}" --param "safety_mode=${safetyMode}" --quiet`;

if (sessionId) {
  cmd += ` --session "${sessionId}"`;
}

return [{ json: { command: cmd, capability, session_id: sessionId } }];

// Parse the executor.sh JSON output and format response
const input = $input.first().json;
const stdout = input.stdout || '';
const stderr = input.stderr || '';
const exitCode = input.exitCode || 0;

let response = '';
let cost = 'unknown';
let model = 'unknown';

try {
  const result = JSON.parse(stdout);
  response = result.result || result.response || stdout;
  cost = result.total_cost_usd || result.cost_usd || 'unknown';
  model = result.model || 'unknown';
} catch (e) {
  response = stdout || stderr || 'No output received';
}

if (exitCode !== 0 && !response) {
  response = `Error (exit code ${exitCode}): ${stderr || 'Unknown error'}`;
}

return [{
  json: {
    response: response,
    cost_usd: cost,
    model: model,
    exit_code: exitCode,
    capability: $('Build Command').first().json.capability,
    session_id: $('Build Command').first().json.session_id
  }
}];
